                                    let name = (h && h.trim()) ? h.trim() : 'Column ' + (idx + 1);
                                    const key = name.toLowerCase();
                                    counts[key] = (counts[key] || 0) + 1;
                                    if (counts[key] > 1) name = name + ' (' + counts[key] + ')';
