                                const initWidth = colCount <= 10 ? (100 / (colCount + 1)).toFixed(2) + '%' : '10%';
                                const colLetter = (idx) => { let s = ''; idx++; while (idx > 0) { idx--; s = String.fromCharCode(65 + (idx % 26)) + s; idx = Math.floor(idx / 26); } return s; };
                                const rowNumW = '42px';
                                // Column visibility dropdown
