                                    html += '<div onmousedown="handlers.startColResize(event,' + c + ')" ondblclick="handlers.autoFitCol(event,' + c + ')" style="position:absolute; right:-6px; top:0; bottom:0; width:12px; cursor:col-resize; z-index:4;"></div>';
                                    html += '</th>';
